#include <stdio.h>

int main() {
    int day = 3;

    switch (day) {
        case 1:
            printf("Monday");
            break;
        case 2:
            printf("Tuesday");
            break;
        case 3:
            printf("Wednesday");
            break;
        default:
            printf("Invalid Day");
    }

    return 0;
}

#include <stdio.h>

int main() {
    int num = 2;

    switch (num) {
        case 1:
        case 2:
        case 3:
            printf("Number is 1, 2, or 3\n");
            break;
        default:
            printf("Number is something else\n");
    }

    return 0;
}
